// Validate input and compute has_failures
const input = $input.first().json;

// Validate required fields
if (!input.summary || !input.results) {
  throw new Error('INVALID_INPUT: Missing summary or results field');
}

const { summary, results, overall_success } = input;

// Compute has_failures (defensive logic)
const has_failures = 
  (summary.failed > 0) ||
  (summary.errors > 0) ||
  (overall_success === false) ||
  results.some(r => r.status !== 'completed' || r.ci_success !== true);

// Split runs into successful and unsuccessful
const successful_runs = results
  .filter(r => r.status === 'completed' && r.ci_success === true)
  .map(r => ({
    target_id: r.target_id,
    run_url: r.run_url
  }));

const unsuccessful_runs = results
  .filter(r => r.status !== 'completed' || r.ci_success !== true)
  .map(r => ({
    target_id: r.target_id,
    status: r.status,
    conclusion: r.conclusion || null,
    error_code: r.error_code || null,
    run_url: r.run_url || null
  }));

console.log('Input validated:', {
  has_failures,
  successful_count: successful_runs.length,
  unsuccessful_count: unsuccessful_runs.length
});

return [{
  json: {
    ...input,
    has_failures,
    successful_runs,
    unsuccessful_runs
  }
}];

// Find tracking issue with exact title match
const TRACKING_TITLE = '[n8n] Automated Tests: Failure detected';

// Pull validated workflow summary directly from the source node.
const validatedData = $('Validate And Classify Suite Result').first().json;

// Current input items are repository issues returned by GitHub node.
// With alwaysOutputData enabled, this list may include a placeholder item when no issues exist.
const issues = $input
  .all()
  .map(item => item.json)
  .filter(issue => typeof issue.title === 'string' && typeof issue.number === 'number');

// Find matching open issue
const matchingIssues = issues
  .filter(issue => issue.title.trim() === TRACKING_TITLE)
  .sort((a, b) => a.number - b.number); // Sort by number (oldest first)

const openIssue = matchingIssues.length > 0 ? matchingIssues[0] : null;
const open_issue_exists = openIssue !== null;

console.log('Issue lookup result:', {
  open_issue_exists,
  issue_number: openIssue?.number || null,
  open_issues_count: issues.length,
  has_failures: validatedData.has_failures
});

return [{
  json: {
    ...validatedData,
    open_issue_exists,
    open_issue: openIssue
  }
}];

// Build failure comment for existing open issue
const data = $input.first().json;
const { summary, successful_runs, unsuccessful_runs } = data;

const successList = successful_runs
  .map(r => `- ✅ [${r.target_id}](${r.run_url})`)
  .join('\n');

const failureList = unsuccessful_runs
  .map(r => {
    const status = r.conclusion || r.error_code || r.status;
    const url = r.run_url ? `[${r.target_id}](${r.run_url})` : r.target_id;
    return `- ❌ ${url} - ${status}`;
  })
  .join('\n');

const body = `## CI Failure Detected\n\n**Summary**: ${summary.failed + summary.errors} of ${summary.total} workflows failed\n\n### Failed Workflows\n${failureList}\n\n### Successful Workflows\n${successList}\n\n---\n*Updated: ${new Date().toISOString()}*`;

return [{
  json: {
    ...data,
    comment_body: body
  }
}];

// Build recovery comment
const data = $input.first().json;
const { summary, successful_runs } = data;

const successList = successful_runs
  .map(r => `- ✅ [${r.target_id}](${r.run_url})`)
  .join('\n');

const body = `## ✅ CI Recovery Detected\n\n**All workflows are now passing!** (${summary.passed}/${summary.total} successful)\n\n### Successful Workflows\n${successList}\n\n---\n*Closing this issue. A new one will be created if failures occur again.*\n*Updated: ${new Date().toISOString()}*`;

return [{
  json: {
    ...data,
    comment_body: body
  }
}];

// Build new issue body
const data = $input.first().json;
const { summary, successful_runs, unsuccessful_runs } = data;

const successList = successful_runs.length > 0
  ? successful_runs.map(r => `- ✅ [${r.target_id}](${r.run_url})`).join('\n')
  : '*None*';

const failureList = unsuccessful_runs
  .map(r => {
    const status = r.conclusion || r.error_code || r.status;
    const url = r.run_url ? `[${r.target_id}](${r.run_url})` : r.target_id;
    return `- ❌ ${url} - ${status}`;
  })
  .join('\n');

const body = `## CI Failure Detected\n\n**Summary**: ${summary.failed + summary.errors} of ${summary.total} workflows failed\n\n### Failed Workflows\n${failureList}\n\n### Successful Workflows\n${successList}\n\n---\n*This issue was automatically created by the n8n CI monitoring workflow.*\n*It will be automatically closed when all CI runs pass.*\n*Created: ${new Date().toISOString()}*`;

return [{
  json: {
    ...data,
    issue_title: '[n8n] Automated Tests: Failure detected',
    issue_body: body
  }
}];

// Return action summary for path 1: commented on existing issue
const data = $input.first().json;

// Extract issue number from issue_url
const issueNumber = data.issue_url
  ? parseInt(data.issue_url.split('/').pop(), 10)
  : null;

return [{
  json: {
    status: 'completed',
    action: 'commented_existing_issue',
    failure_detected: true,
    issue: {
      number: issueNumber,
      state: 'open',
      html_url: data.html_url
    },
    summary: data.body,
    successful_runs: null,
    unsuccessful_runs: 1
  }
}];

// Return action summary for path 2: commented and closed issue
const data = $input.first().json;

return [{
  json: {
    status: 'completed',
    action: 'commented_and_closed_issue',
    failure_detected: false,
    issue: {
      number: data.number,
      state: 'closed',
      html_url: data.html_url
    }
  }
}];

// Return action summary for path 4: no action needed
const data = $input.first().json;

return [{
  json: {
    status: 'completed',
    action: 'no_action',
    failure_detected: false,
    issue: null,
    summary: data.summary,
    successful_runs: data.successful_runs,
    unsuccessful_runs: data.unsuccessful_runs
  }
}];

// Return action summary for path 3: created new issue
const data = $input.first().json;
const createdIssue = $input.first().json;

return [{
  json: {
    status: 'completed',
    action: 'created_new_issue',
    failure_detected: true,
    issue: {
      number: createdIssue.number,
      state: 'open',
      html_url: createdIssue.html_url
    },
    summary: data.summary,
    successful_runs: data.successful_runs,
    unsuccessful_runs: data.unsuccessful_runs
  }
}];

// extract issue id from issue_url, e.g. https://api.github.com/repos/NNTin/gSnake/issues/12
const issueUrl = $input.first().json.issue_url;

const issueNumber = issueUrl
  ? parseInt(issueUrl.split('/').pop(), 10)
  : null;

return [{
  json: {
    issue_number: issueNumber
  }
}];
